// Import web3.js or ethers.js
const Web3 = require('web3');
const ethers = require('ethers');

// Connect to Ethereum node
const web3 = new Web3('YOUR_RPC_ENDPOINT');

// Load private keys
const privateKeys = ['YOUR_PRIVATE_KEY_1', 'YOUR_PRIVATE_KEY_2'];

// Create wallet instances
const wallets = privateKeys.map(key => new ethers.Wallet(key, web3));

// Send ETH
const sendETH = async (toAddress, amount) => {
  const signer = wallets[0].connect(web3);
  const tx = {
    to: toAddress,
    value: web3.utils.toWei(amount, 'ether'),
  };
  const signedTx = await signer.signTransaction(tx);
  await web3.eth.sendSignedTransaction(signedTx);
};

// Interact with smart contracts
const interactWithContract = async (contractAddress, abi, functionName, ...args) => {
  const contract = new ethers.Contract(contractAddress, abi, wallets[0]);
  const transaction = await contract[functionName](...args);
  await transaction.wait();
};

// Example usage
sendETH('0xTO_ADDRESS', '1');
interactWithContract('0xCONTRACT_ADDRESS', 'ABI', 'functionName', 'arg1', 'arg2');